// design-push-figma-components — Button atom sample
// Generated by /design-push-figma-components for 'button' atom
// Variant: primary, Size: md, State: rest
//
// This file is a CONCRETE EXAMPLE of what the skill emits to figma_execute.
// In production, the skill expands this template across the full Cartesian
// product of (variant × size × state) and resolves real Variable ids.
//
// ─────────────────────────────────────────────────────────────────────────
// DIFF-MERGE ALGORITHM (token resolution order)
// ─────────────────────────────────────────────────────────────────────────
// For each component cell (e.g. primary/md/rest), the skill computes the
// final token map using last-write-wins layering:
//
//   1. BASE        — defaults shared by all buttons (radius, font family)
//   2. VARIANT     — primary | secondary | ghost (background, text color)
//   3. SIZE        — sm | md | lg (padding, fontSize, lineHeight)
//   4. STATE       — rest | hover | active | focus | disabled (opacity, ring)
//
// Conflicting keys at a higher layer overwrite lower layers. Example:
//   base.radius        = Radius/Md
//   variant.radius     = (unset)        → keep Radius/Md
//   size.paddingX      = Space/Md       → wins over base.paddingX
//   state.opacity      = 1              → applied last
//
// The merged map is then bound to Figma Variables via setBoundVariable().
// ─────────────────────────────────────────────────────────────────────────

try {
  // ───────────────────────────────────────────────────────────────────────
  // 1. Lookup Variable ids from the 'DS Tokens' collection
  //    The skill resolves <VAR_ID_*> placeholders at runtime by name match.
  // ───────────────────────────────────────────────────────────────────────
  const coll = figma.variables.getLocalVariableCollections()
    .find(c => c.name === 'DS Tokens')
  if (!coll) {
    throw new Error('DS Tokens collection not found — run /design-push-figma-tokens first')
  }

  const varByName = {}
  for (const v of figma.variables.getLocalVariables()) {
    if (v.variableCollectionId === coll.id) varByName[v.name] = v
  }

  // Safe getter — warns but does not throw on missing tokens (graceful degrade)
  const getVar = (name) => {
    const v = varByName[name]
    if (!v) console.warn('[button] Missing variable: ' + name + ' — skipping bind')
    return v
  }

  // ───────────────────────────────────────────────────────────────────────
  // 2. Ensure parent container exists (Section: 'Components')
  // ───────────────────────────────────────────────────────────────────────
  let section = figma.currentPage.findOne(n => n.type === 'SECTION' && n.name === 'Components')
  if (!section) {
    section = figma.createSection()
    section.name = 'Components'
    section.x = 0
    section.y = 0
  }

  // ───────────────────────────────────────────────────────────────────────
  // 3. Create the Component Set (wrapper for all Button variants)
  // ───────────────────────────────────────────────────────────────────────
  const set = figma.createComponentSet()  // <VAR_ID_SET_BUTTON>
  set.name = 'Button'

  // ───────────────────────────────────────────────────────────────────────
  // 4. Create ONE variant frame: primary + md + rest
  //    Full skill loops this block over every (variant × size × state).
  // ───────────────────────────────────────────────────────────────────────
  const comp = figma.createComponent()
  comp.name = 'variant=primary, size=md, state=rest'

  // Auto-layout — horizontal row, hug contents, centered
  comp.layoutMode = 'HORIZONTAL'
  comp.primaryAxisSizingMode = 'AUTO'
  comp.counterAxisSizingMode = 'AUTO'
  comp.primaryAxisAlignItems = 'CENTER'
  comp.counterAxisAlignItems = 'CENTER'

  // ── Bind padding (size layer wins) ──
  const padY = getVar('Space/Sm')   // <VAR_ID_SPACE_SM>
  const padX = getVar('Space/Md')   // <VAR_ID_SPACE_MD>
  if (padY) {
    comp.setBoundVariable('paddingTop', padY.id)
    comp.setBoundVariable('paddingBottom', padY.id)
  }
  if (padX) {
    comp.setBoundVariable('paddingLeft', padX.id)
    comp.setBoundVariable('paddingRight', padX.id)
  }

  // ── Bind gap between icon & label ──
  const gap = getVar('Space/Sm')
  if (gap) comp.setBoundVariable('itemSpacing', gap.id)

  // ── Bind corner radius (base layer — same across all variants) ──
  const rad = getVar('Radius/Md')   // <VAR_ID_RADIUS_MD>
  if (rad) {
    comp.setBoundVariable('topLeftRadius', rad.id)
    comp.setBoundVariable('topRightRadius', rad.id)
    comp.setBoundVariable('bottomLeftRadius', rad.id)
    comp.setBoundVariable('bottomRightRadius', rad.id)
  }

  // ── Bind background fill (variant + state layers) ──
  // primary + rest → Color/Primary/Default
  // primary + hover would resolve to Color/Primary/Hover (skill handles)
  const bg = getVar('Color/Primary/Default')  // <VAR_ID_COLOR_PRIMARY_DEFAULT>
  if (bg) {
    comp.fills = [{
      type: 'SOLID',
      color: { r: 0, g: 0, b: 0 },  // placeholder RGB — overridden by binding
      boundVariables: { color: { type: 'VARIABLE_ALIAS', id: bg.id } }
    }]
  }

  // ── Optional stroke (ghost/secondary variants use this) ──
  // Shown here as pattern; primary/rest has no stroke so skip
  // const strokeVar = getVar('Color/Border/Default')
  // if (strokeVar) comp.strokes = [{ type:'SOLID', color:{r:0,g:0,b:0},
  //   boundVariables: { color: { type:'VARIABLE_ALIAS', id: strokeVar.id }}}]

  // ───────────────────────────────────────────────────────────────────────
  // 5. Add text label (font must be loaded by skill before figma_execute)
  // ───────────────────────────────────────────────────────────────────────
  const text = figma.createText()
  text.characters = 'Button'
  text.fontName = { family: 'Inter', style: 'Semi Bold' }

  // Bind typography tokens (size layer)
  const fontSize = getVar('Size/Md')             // <VAR_ID_SIZE_MD>
  const lh       = getVar('Leading/Normal')      // <VAR_ID_LEADING_NORMAL>
  const tracking = getVar('Tracking/Normal')     // <VAR_ID_TRACKING_NORMAL>
  if (fontSize) text.setBoundVariable('fontSize', fontSize.id)
  if (lh)       text.setBoundVariable('lineHeight', lh.id)
  if (tracking) text.setBoundVariable('letterSpacing', tracking.id)

  // Bind text color (variant layer — On-bgcolor pairs with primary bg)
  const textColor = getVar('Color/Text/On-bgcolor')  // <VAR_ID_COLOR_TEXT_ON_BG>
  if (textColor) {
    text.fills = [{
      type: 'SOLID',
      color: { r: 1, g: 1, b: 1 },
      boundVariables: { color: { type: 'VARIABLE_ALIAS', id: textColor.id } }
    }]
  }

  comp.appendChild(text)
  set.appendChild(comp)
  section.appendChild(set)

  // ───────────────────────────────────────────────────────────────────────
  // 6. (skipped here) Loop remaining variants
  //    Full skill emits ~3 variants × 3 sizes × 5 states = 45 components.
  //    Component Properties are added AFTER all frames are in the set:
  //
  //    set.addComponentProperty('variant', 'VARIANT', 'primary')
  //    set.addComponentProperty('size',    'VARIANT', 'md')
  //    set.addComponentProperty('state',   'VARIANT', 'rest')
  // ───────────────────────────────────────────────────────────────────────

  console.log('[button] OK — 1 variant created (primary/md/rest)')
  console.log('[button] Total Component Sets on page: ' +
    figma.currentPage.findAll(n => n.type === 'COMPONENT_SET').length)

} catch (err) {
  // Error pattern — surface failure clearly so the skill can retry or abort
  console.error('[button] FAILED: ' + err.message)
  throw err  // re-throw so figma_execute returns non-zero to the skill
}
